@Composable
private fun AnimeScreen(
    onAnimeSelected: (AnimeEntry) -> Unit,
    customCategories: List<String>,
    statusOverrides: Map<Int, String>,
    categoryAssignments: Map<Int, Set<String>>,
    libraryMessage: String,
    isScanning: Boolean,
    onRescan: () -> Unit
) {
    val statusCategories = remember {
        AnimeCategory.entries.map { it.label }
    }
    val libraryFilters = remember(customCategories) {
        listOf("All") + customCategories
    }

    val pagerState = rememberPagerState(
        initialPage = 0,
        pageCount = { statusCategories.size }
    )
    val scope = rememberCoroutineScope()
    val context = LocalContext.current
    val morePreferences = remember {
        context.getSharedPreferences(
            "inku_more_settings",
            Context.MODE_PRIVATE
        )
    }
    val downloadedOnly = morePreferences.getBoolean(
        "downloaded_only",
        false
    )

    var searchVisible by rememberSaveable { mutableStateOf(false) }
    var searchQuery by rememberSaveable { mutableStateOf("") }
    var filtersVisible by rememberSaveable { mutableStateOf(false) }
    var selectedType by rememberSaveable { mutableStateOf("All") }
    var selectedLibraryCategory by rememberSaveable { mutableStateOf("All") }

    if (selectedLibraryCategory !in libraryFilters) {
        selectedLibraryCategory = "All"
    }

    val refreshRotation = remember { Animatable(0f) }

    LaunchedEffect(isScanning) {
        if (isScanning) {
            while (true) {
                refreshRotation.animateTo(
                    targetValue = refreshRotation.value + 360f,
                    animationSpec = tween(
                        durationMillis = if (InkuRuntimeSettings.smoothAnimations) 760 else 1,
                        easing = LinearEasing
                    )
                )
            }
        } else {
            refreshRotation.snapTo(0f)
        }
    }

    fun matchesCommonFilters(anime: AnimeEntry): Boolean {
        val customMatch = selectedLibraryCategory == "All" ||
                selectedLibraryCategory in categoryAssignments[anime.id].orEmpty()
        return customMatch &&
                (!downloadedOnly || hasQueuedDownload(context, anime.title)) &&
                (selectedType == "All" || anime.type == selectedType) &&
                (searchQuery.isBlank() || anime.title.contains(searchQuery, ignoreCase = true))
    }

    val categoryCounts = statusCategories.associateWith { statusName ->
        animeLibrary.count { anime ->
            val assignedStatus = statusOverrides[anime.id] ?: anime.category.label
            assignedStatus == statusName && matchesCommonFilters(anime)
        }
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .imePadding()
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .statusBarsPadding()
                .padding(top = 12.dp)
        ) {
            AnimeHeader(
                searchVisible = searchVisible,
                searchQuery = searchQuery,
                onSearchQueryChange = { searchQuery = it },
                onSearchToggle = {
                    searchVisible = !searchVisible
                    if (!searchVisible) searchQuery = ""
                },
                onFilterToggle = { filtersVisible = !filtersVisible },
                isRefreshing = isScanning,
                refreshRotation = refreshRotation.value,
                onRefresh = {
                    if (!isScanning) onRescan()
                }
            )

            RefreshStatus(
                message = libraryMessage,
                highlighted = isScanning
            )

            AnimatedVisibility(
                visible = filtersVisible,
                enter = fadeIn(tween(180)) + expandVertically(tween(260)),
                exit = fadeOut(tween(120)) + shrinkVertically(tween(220))
            ) {
                Column {
                    AnimeTypeFilters(
                        selectedType = selectedType,
                        onTypeSelected = { selectedType = it }
                    )
                    if (customCategories.isNotEmpty()) {
                        LibraryCategoryFilter(
                            title = "Library category",
                            categories = libraryFilters,
                            selected = selectedLibraryCategory,
                            onSelected = { selectedLibraryCategory = it }
                        )
                    }
                }
            }

            AnimeCategoryTabs(
                categories = statusCategories,
                categoryCounts = categoryCounts,
                selectedIndex = pagerState.currentPage,
                onCategorySelected = { index ->
                    scope.launch { pagerState.animateScrollToPage(index) }
                }
            )

            HorizontalPager(
                state = pagerState,
                modifier = Modifier
                    .fillMaxSize()
                    .clipToBounds(),
                pageSpacing = 0.dp,
                beyondViewportPageCount = 0
            ) { page ->
                val statusName = statusCategories[page]
                val visibleAnime = animeLibrary.filter { anime ->
                    val assignedStatus = statusOverrides[anime.id] ?: anime.category.label
                    assignedStatus == statusName && matchesCommonFilters(anime)
                }

                AnimeGrid(
                    anime = visibleAnime,
                    categoryLabel = statusName,
                    onAnimeSelected = onAnimeSelected
                )
            }
        }
    }
}

@Composable
private fun LibraryCategoryFilter(
    title: String,
    categories: List<String>,
    selected: String,
    onSelected: (String) -> Unit
) {
    Column(
        modifier = Modifier.fillMaxWidth()
    ) {
        Text(
            text = title,
            color = InkuMutedText,
            fontSize = 10.sp,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.padding(horizontal = 16.dp, vertical = 3.dp)
        )
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .horizontalScroll(rememberScrollState())
                .padding(horizontal = 16.dp, vertical = 4.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            categories.forEach { category ->
                val isSelected = category == selected
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(14.dp))
                        .background(
                            if (isSelected) InkuMint else InkuNavigation.copy(alpha = 0.70f)
                        )
                        .clickable { onSelected(category) }
                        .padding(horizontal = 14.dp, vertical = 7.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = category,
                        color = if (isSelected) InkuDarkText else InkuText,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.ExtraBold
                    )
                }
            }
        }
    }
}

@Composable
private fun AnimeHeader(
    searchVisible: Boolean,
    searchQuery: String,
    onSearchQueryChange: (String) -> Unit,
    onSearchToggle: () -> Unit,
    onFilterToggle: () -> Unit,
    isRefreshing: Boolean,
    refreshRotation: Float,
    onRefresh: () -> Unit
) {
    Column(
        modifier = Modifier.fillMaxWidth()
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = "Anime",
                color = InkuText,
                fontSize = 29.sp,
                fontWeight = FontWeight.ExtraBold,
                modifier = Modifier.weight(1f)
            )

            TopActionBar(
                onSearch = onSearchToggle,
                onFilter = onFilterToggle,
                onRefresh = onRefresh,
                isRefreshing = isRefreshing,
                refreshRotation = refreshRotation
            )
        }

        AnimatedVisibility(
            visible = searchVisible,
            enter = fadeIn(
                animationSpec = tween(durationMillis = 180)
            ) + expandVertically(
                animationSpec = tween(
                    durationMillis = 260,
                    easing = FastOutSlowInEasing
                ),
                expandFrom = Alignment.Top
            ) + slideInVertically(
                animationSpec = tween(durationMillis = 240),
                initialOffsetY = { -it / 3 }
