                animationSpec = tween(
                    durationMillis = 210,
                    easing = FastOutSlowInEasing
                ),
                shrinkTowards = Alignment.Top
            ) + slideOutVertically(
                animationSpec = tween(durationMillis = 180),
                targetOffsetY = { -it / 4 }
            )
        ) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(52.dp)
                    .padding(horizontal = 16.dp, vertical = 6.dp)
            ) {
