@Composable
private fun ActionIconButton(
    type: InkuIconType,
    contentDescription: String,
    onClick: () -> Unit,
    enabled: Boolean = true,
    rotation: Float = 0f
) {
    val alpha by animateFloatAsState(
        targetValue = if (enabled) 1f else 0.62f,
        animationSpec = tween(durationMillis = 180),
        label = "${contentDescription}Alpha"
    )

    Box(
        modifier = Modifier
            .size(36.dp)
            .alpha(alpha)
            .clip(CircleShape)
            .clickable(
                enabled = enabled,
                onClick = onClick
            ),
        contentAlignment = Alignment.Center
    ) {
        InkuIcon(
            type = type,
            tint = InkuDarkText,
            modifier = Modifier
                .size(22.dp)
                .graphicsLayer {
                    rotationZ = rotation
                }
        )
    }
}

@Composable
private fun RefreshStatus(
    message: String,
    highlighted: Boolean
) {
    val background by animateColorAsState(
        targetValue = if (highlighted) {
            InkuMint.copy(alpha = 0.20f)
        } else {
            Color.Transparent
        },
        animationSpec = tween(durationMillis = 250),
        label = "refreshStatusBackground"
    )

    val textColor by animateColorAsState(
        targetValue = if (highlighted) InkuMint else InkuMutedText,
        animationSpec = tween(durationMillis = 250),
        label = "refreshStatusText"
    )

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 5.dp)
            .clip(RoundedCornerShape(12.dp))
            .background(background)
            .padding(horizontal = 10.dp, vertical = 4.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(
            modifier = Modifier
                .size(6.dp)
                .clip(CircleShape)
                .background(
                    if (highlighted) InkuMint else InkuMutedText
                )
        )

        Spacer(modifier = Modifier.width(7.dp))

        Text(
            text = message,
            color = textColor,
            fontSize = 11.sp,
            fontWeight = FontWeight.SemiBold
        )
    }
