private fun renderRating(rating: Float): String {
    val fullStars = rating.toInt().coerceIn(0, 5)
    val stars = "★".repeat(fullStars) + "☆".repeat(5 - fullStars)
    return "$stars  ${String.format("%.1f", rating)}"
}

