            if (!videoUri.isNullOrBlank()) {
                EpisodeVideoThumbnail(
                    uriString = videoUri,
                    cacheKey = videoCacheKey,
                    modifier = Modifier.fillMaxSize(),
                    fallbackText = "E$seasonEpisode"
                )
                Box(
                    modifier = Modifier
                        .align(Alignment.Center)
                        .size(28.dp)
                        .clip(CircleShape)
                        .background(Color.Black.copy(alpha = 0.58f)),
                    contentAlignment = Alignment.Center
                ) {
                    Text("▶", color = Color.White, fontSize = 12.sp)
                }
            } else {
                Text(
                    text = "E$seasonEpisode",
                    color = InkuText,
                    fontSize = 14.sp,
                    fontWeight = FontWeight.Black
                )
            }

            if (watched) {
                Box(
                    modifier = Modifier
                        .align(Alignment.TopEnd)
                        .padding(5.dp)
                        .size(20.dp)
                        .clip(CircleShape)
                        .background(InkuMint),
                    contentAlignment = Alignment.Center
                ) {
                    Text("✓", color = InkuDarkText, fontSize = 10.sp, fontWeight = FontWeight.Black)
                }
            }
        }

        Spacer(modifier = Modifier.width(12.dp))

        Column(modifier = Modifier.weight(1f)) {
            Text(
                text = if (displayMode == EpisodeDisplayMode.Titles) title else "Episode $episode",
                color = InkuText,
                fontSize = 13.sp,
                lineHeight = 16.sp,
                fontWeight = FontWeight.Bold,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis
            )
            Text(
                text = when {
                    watched -> "Watched"
                    isNext -> "Up next"
                    videoUri.isNullOrBlank() -> "Video file missing"
                    else -> "Not watched"
                },
                color = if (isNext) InkuMint else InkuMutedText,
                fontSize = 10.sp
            )
        }
    }
}

