@Composable
private fun MangaScreen(
    onMangaSelected: (MangaEntry) -> Unit,
    customCategories: List<String>,
    shelfOverrides: Map<Int, String>,
    categoryAssignments: Map<Int, Set<String>>,
    libraryMessage: String,
    isScanning: Boolean,
    onRescan: () -> Unit
) {
    val context = LocalContext.current
    val morePreferences = remember {
        context.getSharedPreferences("inku_more_settings", Context.MODE_PRIVATE)
    }
    val downloadedOnly = morePreferences.getBoolean("downloaded_only", false)

    var selectedShelf by rememberSaveable { mutableStateOf("Reading") }
    var selectedLibraryCategory by rememberSaveable { mutableStateOf("All") }
    val refreshRotation = remember { Animatable(0f) }

    LaunchedEffect(isScanning) {
        if (isScanning) {
            while (true) {
                refreshRotation.animateTo(
                    targetValue = refreshRotation.value + 360f,
                    animationSpec = tween(
                        durationMillis = if (InkuRuntimeSettings.smoothAnimations) 760 else 1,
                        easing = LinearEasing
                    )
                )
            }
        } else {
            refreshRotation.snapTo(0f)
        }
    }

    val shelves = listOf("Reading", "Plan to Read", "Completed", "Dropped")
    val libraryFilters = listOf("All") + customCategories
    if (selectedLibraryCategory !in libraryFilters) selectedLibraryCategory = "All"

    val visibleManga = mangaLibrary.filter { manga ->
        val shelf = shelfOverrides[manga.id] ?: manga.shelf
        val categoryMatch = selectedLibraryCategory == "All" ||
                selectedLibraryCategory in categoryAssignments[manga.id].orEmpty()
        shelf == selectedShelf &&
                categoryMatch &&
                (!downloadedOnly || hasQueuedDownload(context, manga.title))
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .statusBarsPadding()
            .padding(top = 12.dp)
    ) {
        PageHeader(
            title = "Manga",
            subtitle = "Keep your reading progress in one clean library.",
            icon = InkuIconType.Manga
        )

        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 4.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = libraryMessage,
                color = if (isScanning) InkuMint else InkuMutedText,
                fontSize = 11.sp,
                fontWeight = FontWeight.SemiBold,
                modifier = Modifier.weight(1f),
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )

            ActionIconButton(
                type = InkuIconType.Refresh,
                contentDescription = "Rescan manga folders",
                onClick = onRescan,
                enabled = !isScanning,
                rotation = refreshRotation.value
            )
        }

        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 10.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            LibraryStat(
                label = "Reading",
                value = mangaLibrary.count {
                    (shelfOverrides[it.id] ?: it.shelf) == "Reading"
                }.toString(),
                modifier = Modifier.weight(1f)
            )
            LibraryStat(
                label = "Planned",
                value = mangaLibrary.count {
                    (shelfOverrides[it.id] ?: it.shelf) == "Plan to Read"
                }.toString(),
                modifier = Modifier.weight(1f)
            )
            LibraryStat(
                label = "Finished",
                value = mangaLibrary.count {
                    (shelfOverrides[it.id] ?: it.shelf) == "Completed"
                }.toString(),
                modifier = Modifier.weight(1f)
            )
        }

        if (customCategories.isNotEmpty()) {
            LibraryCategoryFilter(
                title = "Library category",
                categories = libraryFilters,
                selected = selectedLibraryCategory,
                onSelected = { selectedLibraryCategory = it }
            )
        }

        Row(
            modifier = Modifier
                .fillMaxWidth()
                .horizontalScroll(rememberScrollState())
                .padding(horizontal = 16.dp, vertical = 5.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            shelves.forEach { shelf ->
                val selected = selectedShelf == shelf
                val background by animateColorAsState(
                    targetValue = if (selected) InkuMint
                    else InkuNavigation.copy(alpha = 0.68f),
                    animationSpec = tween(
                        durationMillis = if (InkuRuntimeSettings.smoothAnimations) 220 else 0
                    ),
                    label = "${shelf}ShelfBackground"
                )

                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(17.dp))
                        .background(background)
                        .clickable { selectedShelf = shelf }
                        .padding(horizontal = 16.dp, vertical = 9.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = shelf,
                        color = if (selected) InkuDarkText else InkuText,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.ExtraBold
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(8.dp))

        if (visibleManga.isEmpty()) {
            EmptyCategoryState(
                categoryLabel = if (selectedLibraryCategory == "All") {
                    selectedShelf
                } else {
                    "$selectedShelf • $selectedLibraryCategory"
                }
            )
        } else {
            LazyVerticalGrid(
                columns = GridCells.Fixed(
                    if (InkuRuntimeSettings.compactCards) 4 else 3
                ),
                modifier = Modifier
                    .fillMaxSize()
                    .padding(horizontal = 10.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalArrangement = Arrangement.spacedBy(9.dp),
                contentPadding = PaddingValues(bottom = 118.dp)
            ) {
                items(
                    items = visibleManga,
                    key = { it.id }
                ) { entry ->
                    MangaCard(
                        manga = entry,
                        onClick = { onMangaSelected(entry) }
                    )
                }
            }
        }
    }
}

@Composable
private fun MangaCard(
    manga: MangaEntry,
    onClick: () -> Unit
) {
    val context = LocalContext.current
    val preferences = remember {
        context.getSharedPreferences("inku_profile_edits", Context.MODE_PRIVATE)
    }
    val title = preferences.getString("manga_${manga.id}_title", manga.title) ?: manga.title
    val coverUri = preferences.getString("manga_${manga.id}_cover_uri", manga.coverUri.ifBlank { null })
    val currentChapter = preferences.getInt(
        "manga_${manga.id}_current_chapter",
        manga.currentChapter
    )
    val progress = if (manga.totalChapters > 0) {
        currentChapter.toFloat() / manga.totalChapters.toFloat()
    } else 0f

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .aspectRatio(0.68f)
            .clip(RoundedCornerShape(11.dp))
            .background(
                Brush.linearGradient(
                    colors = listOf(manga.colorStart, manga.colorEnd),
                    start = Offset.Zero,
                    end = Offset.Infinite
                )
            )
            .clickable(onClick = onClick)
    ) {
        if (!coverUri.isNullOrBlank()) {
            ProfileImage(
                uriString = coverUri,
                contentDescription = "$title cover",
                modifier = Modifier.fillMaxSize(),
                contentScale = ContentScale.Crop
            )
        } else {
            Text(
                text = title.take(1).uppercase(),
                color = InkuText.copy(alpha = 0.15f),
                fontSize = if (InkuRuntimeSettings.compactCards) 42.sp else 58.sp,
                fontWeight = FontWeight.Black,
                modifier = Modifier.align(Alignment.Center)
            )
        }

        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(
                    Brush.verticalGradient(
                        listOf(
                            Color.Transparent,
                            InkuNavigation.copy(alpha = 0.12f),
                            InkuNavigation.copy(alpha = 0.95f)
                        )
                    )
                )
        )

        Column(
            modifier = Modifier
                .align(Alignment.BottomStart)
                .fillMaxWidth()
                .padding(if (InkuRuntimeSettings.compactCards) 6.dp else 8.dp)
        ) {
            Text(
                text = title,
                color = InkuText,
                fontSize = if (InkuRuntimeSettings.compactCards) 9.sp else 11.sp,
                lineHeight = if (InkuRuntimeSettings.compactCards) 11.sp else 13.sp,
                fontWeight = FontWeight.ExtraBold,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis
            )

            Spacer(modifier = Modifier.height(5.dp))

            Text(
                text = "$currentChapter/${manga.totalChapters} chapters",
                color = InkuText.copy(alpha = 0.82f),
                fontSize = 8.sp,
                fontWeight = FontWeight.SemiBold
            )

            if (InkuRuntimeSettings.showProgress) {
                Spacer(modifier = Modifier.height(5.dp))
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(4.dp)
                        .clip(RoundedCornerShape(4.dp))
                        .background(InkuText.copy(alpha = 0.18f))
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth(progress.coerceIn(0f, 1f))
                            .height(4.dp)
                            .clip(RoundedCornerShape(4.dp))
                            .background(InkuMint)
                    )
                }
            }
        }
    }
}

@Composable
private fun UpdatesScreen() {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val rotation = remember { Animatable(0f) }
    var isChecking by remember { mutableStateOf(false) }
    var refreshToken by remember { mutableIntStateOf(0) }
    var records by remember(refreshToken) { mutableStateOf(DownloadStore.list(context)) }
    var status by remember { mutableStateOf("Library and downloads are ready") }

    LaunchedEffect(Unit) {
        while (true) {
            records = DownloadStore.list(context)
            delay(1_000)
        }
    }

    val activeRecords = records.filter {
        it.state in setOf(
            InkuDownloadState.Queued,
            InkuDownloadState.Running,
            InkuDownloadState.Paused
        )
    }
    val completedRecords = records.filter { it.state == InkuDownloadState.Completed }
    val failedRecords = records.filter { it.state == InkuDownloadState.Failed }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .statusBarsPadding()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 16.dp, vertical = 12.dp)
            .padding(bottom = 118.dp)
    ) {
        Row(verticalAlignment = Alignment.CenterVertically) {
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = "Updates",
                    color = InkuText,
                    fontSize = 29.sp,
                    fontWeight = FontWeight.ExtraBold
                )
                Text(
                    text = status,
                    color = if (isChecking) InkuMint else InkuMutedText,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.SemiBold
                )
            }

            Box(
                modifier = Modifier
                    .size(48.dp)
                    .clip(CircleShape)
                    .background(InkuMint)
                    .clickable(enabled = !isChecking) {
                        isChecking = true
                        status = "Refreshing local library and download status…"
                        scope.launch {
                            rotation.snapTo(0f)
                            rotation.animateTo(
                                targetValue = 720f,
                                animationSpec = tween(
                                    durationMillis = 1_200,
                                    easing = LinearEasing
                                )
                            )
                            refreshToken += 1
                            records = DownloadStore.list(context)
                            status = "Updated just now"
                            isChecking = false
                        }
                    },
                contentAlignment = Alignment.Center
            ) {
                InkuIcon(
                    type = InkuIconType.Refresh,
                    tint = InkuDarkText,
                    modifier = Modifier
                        .size(24.dp)
                        .graphicsLayer { rotationZ = rotation.value }
                )
            }
        }

        Spacer(modifier = Modifier.height(18.dp))

        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            UpdateSummaryCard("Anime", animeLibrary.size.toString(), Modifier.weight(1f))
            UpdateSummaryCard("Manga", mangaLibrary.size.toString(), Modifier.weight(1f))
            UpdateSummaryCard("Active", activeRecords.size.toString(), Modifier.weight(1f))
        }

        SettingsSectionTitle("Download activity")

        when {
            records.isEmpty() -> InfoPanel(
                title = "No real activity yet",
                body = "Updates appear here after Inku scans local files or starts a real download. Demo titles are not inserted."
            )

            else -> {
                activeRecords.forEach { record ->
                    DownloadRecordCard(
                        record = record,
                        onRetry = {},
                        onRemove = {
                            DownloadStore.remove(context, record)
                            records = DownloadStore.list(context)
                        }
                    )
                }
                completedRecords.take(8).forEach { record ->
                    DownloadRecordCard(
                        record = record,
                        onRetry = {},
                        onRemove = {
                            DownloadStore.remove(context, record)
                            records = DownloadStore.list(context)
                        }
                    )
                }
                failedRecords.take(8).forEach { record ->
                    DownloadRecordCard(
                        record = record,
                        onRetry = {
                            DownloadStore.retry(context, record)
                            records = DownloadStore.list(context)
                        },
                        onRemove = {
                            DownloadStore.remove(context, record)
                            records = DownloadStore.list(context)
                        }
                    )
                }
            }
        }
    }
}

