private fun createInkuFolders(
    context: Context
): String {
    return runCatching {
        val root = File(
            context.getExternalFilesDir(null),
            "Inku"
        )

        listOf(
            "Downloads",
            "Local Anime",
            "Local Manga",
            "Subtitles"
        ).forEach { folderName ->
            File(
                root,
                folderName
            ).mkdirs()
        }

        "The local Inku folder structure is ready."
    }.getOrElse {
        "The folder structure could not be created."
    }
}

