@Composable
private fun MiniSwitch(
    enabled: Boolean,
    onClick: () -> Unit
) {
    val background by animateColorAsState(
        targetValue = if (enabled) InkuMint else InkuNavigationSoft,
        animationSpec = tween(durationMillis = 220),
        label = "MiniSwitchBackground"
    )

    val offset by animateDpAsState(
        targetValue = if (enabled) 20.dp else 2.dp,
        animationSpec = tween(
            durationMillis = 220,
            easing = FastOutSlowInEasing
        ),
        label = "MiniSwitchOffset"
    )

    Box(
        modifier = Modifier
            .width(42.dp)
            .height(24.dp)
            .clip(RoundedCornerShape(12.dp))
            .background(background)
            .clickable(onClick = onClick)
    ) {
        Box(
            modifier = Modifier
                .padding(
                    start = offset,
                    top = 2.dp
                )
                .size(20.dp)
                .clip(CircleShape)
                .background(
                    if (enabled) InkuDarkText else InkuMutedText
                )
        )
    }
}


@Composable
private fun InkuBottomNavigation(
    selectedPage: Int,
    onPageSelected: (Int) -> Unit,
    modifier: Modifier = Modifier
) {
    Box(
        modifier = modifier
            .fillMaxWidth()
            .navigationBarsPadding()
            .padding(horizontal = 16.dp, vertical = 12.dp)
            .clip(RoundedCornerShape(22.dp))
            .background(InkuNavigation.copy(alpha = 0.94f))
            .padding(6.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .height(64.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            MainPage.entries.forEachIndexed { index, page ->
                val selected = selectedPage == index

                val background by animateColorAsState(
                    targetValue = if (selected) {
                        InkuMint
                    } else {
                        Color.Transparent
                    },
                    animationSpec = tween(
                        durationMillis = 260,
                        easing = FastOutSlowInEasing
                    ),
                    label = "${page.name}BottomBackground"
                )

                val scale by animateFloatAsState(
                    targetValue = if (selected) 1f else 0.92f,
                    animationSpec = tween(
                        durationMillis = 240,
                        easing = FastOutSlowInEasing
                    ),
                    label = "${page.name}BottomScale"
                )

                Column(
                    modifier = Modifier
                        .weight(1f)
                        .fillMaxSize()
                        .graphicsLayer {
                            scaleX = scale
                            scaleY = scale
                        }
                        .clip(RoundedCornerShape(17.dp))
                        .background(background)
                        .clickable { onPageSelected(index) },
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    InkuIcon(
                        type = page.icon,
                        tint = if (selected) InkuDarkText else InkuText
                    )

                    Spacer(modifier = Modifier.height(3.dp))

                    Text(
                        text = page.label,
                        color = if (selected) InkuDarkText else InkuText,
                        fontSize = 10.sp,
                        fontWeight = FontWeight.ExtraBold,
                        maxLines = 1
                    )
                }
            }
        }
    }
}

private enum class InkuIconType {
    Search,
    Filter,
    Refresh,
    Anime,
    Manga,
    Browse,
    Settings
}

@Composable
private fun InkuIcon(
    type: InkuIconType,
    tint: Color,
    modifier: Modifier = Modifier
) {
    Canvas(
        modifier = modifier.size(22.dp)
    ) {
        val stroke = 2.dp.toPx()
        val thinStroke = 1.5.dp.toPx()
        val center = Offset(
            x = size.width / 2f,
            y = size.height / 2f
        )

        when (type) {
            InkuIconType.Search -> {
                drawCircle(
                    color = tint,
                    radius = size.width * 0.28f,
                    center = Offset(
                        x = size.width * 0.42f,
                        y = size.height * 0.42f
                    ),
                    style = Stroke(
                        width = stroke,
                        cap = StrokeCap.Round
                    )
                )

                drawLine(
                    color = tint,
                    start = Offset(
                        x = size.width * 0.62f,
                        y = size.height * 0.62f
                    ),
                    end = Offset(
                        x = size.width * 0.88f,
                        y = size.height * 0.88f
                    ),
                    strokeWidth = stroke,
                    cap = StrokeCap.Round
                )
            }

            InkuIconType.Filter -> {
                val linePositions = listOf(
                    size.height * 0.25f,
                    size.height * 0.50f,
                    size.height * 0.75f
                )

                linePositions.forEach { yPosition ->
                    drawLine(
                        color = tint,
                        start = Offset(
                            x = size.width * 0.12f,
                            y = yPosition
                        ),
                        end = Offset(
                            x = size.width * 0.88f,
                            y = yPosition
                        ),
                        strokeWidth = thinStroke,
                        cap = StrokeCap.Round
                    )
                }

                drawCircle(
                    color = tint,
                    radius = stroke,
                    center = Offset(
                        x = size.width * 0.38f,
                        y = linePositions[0]
                    )
                )

                drawCircle(
                    color = tint,
                    radius = stroke,
                    center = Offset(
                        x = size.width * 0.67f,
                        y = linePositions[1]
                    )
                )

                drawCircle(
                    color = tint,
                    radius = stroke,
                    center = Offset(
                        x = size.width * 0.45f,
                        y = linePositions[2]
                    )
                )
            }

            InkuIconType.Refresh -> {
                drawArc(
                    color = tint,
                    startAngle = -60f,
                    sweepAngle = 285f,
                    useCenter = false,
                    topLeft = Offset(
                        x = stroke,
                        y = stroke
                    ),
                    size = androidx.compose.ui.geometry.Size(
                        width = size.width - stroke * 2,
                        height = size.height - stroke * 2
                    ),
                    style = Stroke(
                        width = stroke,
                        cap = StrokeCap.Round
                    )
                )

                drawLine(
                    color = tint,
                    start = Offset(
                        x = size.width * 0.72f,
                        y = size.height * 0.08f
                    ),
                    end = Offset(
                        x = size.width * 0.93f,
                        y = size.height * 0.12f
                    ),
                    strokeWidth = stroke,
                    cap = StrokeCap.Round
                )

                drawLine(
                    color = tint,
                    start = Offset(
                        x = size.width * 0.93f,
                        y = size.height * 0.12f
                    ),
                    end = Offset(
                        x = size.width * 0.87f,
                        y = size.height * 0.33f
                    ),
                    strokeWidth = stroke,
                    cap = StrokeCap.Round
                )
            }

            InkuIconType.Anime -> {
                drawCircle(
                    color = tint,
                    radius = size.width * 0.43f,
                    center = center,
                    style = Stroke(width = stroke)
                )

                val playPath = Path().apply {
                    moveTo(
                        x = size.width * 0.42f,
                        y = size.height * 0.31f
                    )
                    lineTo(
                        x = size.width * 0.72f,
                        y = size.height * 0.50f
                    )
                    lineTo(
                        x = size.width * 0.42f,
                        y = size.height * 0.69f
                    )
                    close()
                }

                drawPath(
                    path = playPath,
                    color = tint
                )
            }

            InkuIconType.Manga -> {
                val leftPage = Path().apply {
                    moveTo(
                        x = size.width * 0.08f,
                        y = size.height * 0.18f
                    )
                    lineTo(
                        x = size.width * 0.45f,
                        y = size.height * 0.18f
                    )
                    lineTo(
                        x = size.width * 0.45f,
                        y = size.height * 0.84f
                    )
                    lineTo(
                        x = size.width * 0.08f,
                        y = size.height * 0.75f
                    )
                    close()
                }

                val rightPage = Path().apply {
                    moveTo(
                        x = size.width * 0.55f,
                        y = size.height * 0.18f
                    )
                    lineTo(
                        x = size.width * 0.92f,
                        y = size.height * 0.18f
                    )
                    lineTo(
                        x = size.width * 0.92f,
                        y = size.height * 0.75f
                    )
                    lineTo(
                        x = size.width * 0.55f,
                        y = size.height * 0.84f
                    )
                    close()
                }

                drawPath(
                    path = leftPage,
                    color = tint,
                    style = Stroke(width = thinStroke)
                )

                drawPath(
                    path = rightPage,
                    color = tint,
                    style = Stroke(width = thinStroke)
                )
            }

            InkuIconType.Browse -> {
                drawCircle(
                    color = tint,
                    radius = size.width * 0.43f,
                    center = center,
                    style = Stroke(width = thinStroke)
                )

                drawLine(
                    color = tint,
                    start = Offset(
                        x = size.width * 0.12f,
                        y = center.y
                    ),
                    end = Offset(
                        x = size.width * 0.88f,
                        y = center.y
                    ),
                    strokeWidth = thinStroke
                )

                drawOval(
                    color = tint,
                    topLeft = Offset(
                        x = size.width * 0.31f,
                        y = size.height * 0.07f
                    ),
                    size = androidx.compose.ui.geometry.Size(
                        width = size.width * 0.38f,
                        height = size.height * 0.86f
                    ),
                    style = Stroke(width = thinStroke)
                )
            }

            InkuIconType.Settings -> {
                listOf(
                    0.28f,
                    0.50f,
                    0.72f
                ).forEach { xPosition ->
                    drawCircle(
                        color = tint,
                        radius = size.width * 0.09f,
                        center = Offset(
                            x = size.width * xPosition,
                            y = center.y
                        )
                    )
                }
            }
        }
    }
}

